UPDATE email_templates SET html_content = E'Bonjour {{first_name}},\n\n{{#is_first_day}}C''est le grand jour ! Ta formation <strong>"{{training_name}}"</strong> commence aujourd''hui.{{/is_first_day}}{{#is_next_day}}Ta formation <strong>"{{training_name}}"</strong> continue aujourd''hui !{{/is_next_day}}\n\n{{#is_presentiel}}<strong>📍 Infos pratiques :</strong>\n<ul>\n<li>Lieu : {{location}}</li>\n<li>Horaires : {{schedule}}</li>\n</ul>\nPense à arriver quelques minutes en avance pour t''installer confortablement.{{/is_presentiel}}{{#is_classe_virtuelle}}<strong>💻 Infos de connexion :</strong>\n<ul>\n{{#meeting_url}}<li>Lien visio : <a href="{{meeting_url}}">Rejoindre la classe virtuelle</a></li>\n{{/meeting_url}}<li>Horaires : {{schedule}}</li>\n</ul>\nAssure-toi d''avoir une connexion stable et un endroit au calme.{{/is_classe_virtuelle}}{{#is_elearning}}<strong>🎓 Ta formation e-learning continue !</strong>\n{{#meeting_url}}<p><a href="{{meeting_url}}">Accéder à la formation</a></p>\n{{/meeting_url}}Connecte-toi à ton espace pour poursuivre ta formation.{{/is_elearning}}\n\nÀ tout à l''heure !' WHERE template_type = 'today_reminder_tu';

